import{_ as e,o as t,c as n,R as a}from"./chunks/framework.JncSVmEt.js";const o="/ChimeIn2.0/assets/app-tab.v-5Rzton.png",s="/ChimeIn2.0/assets/delete-placement.NIpHschs.png",i="/ChimeIn2.0/assets/externaltool.3FRBPH2v.png",r="/ChimeIn2.0/assets/externaltool-select-list.ubXPOkXr.png",I=JSON.parse('{"title":"Updating Canvas to LTI 1.3","description":"","frontmatter":{},"headers":[],"relativePath":"lti11-migration.md","filePath":"lti11-migration.md","lastUpdated":null}'),l={name:"lti11-migration.md"},p=a('<h1 id="updating-canvas-to-lti-1-3" tabindex="-1">Updating Canvas to LTI 1.3 <a class="header-anchor" href="#updating-canvas-to-lti-1-3" aria-label="Permalink to &quot;Updating Canvas to LTI 1.3&quot;">​</a></h1><p>When older Canvas courses are cloned, they can bring forward ChimeIn configurations that use an older technology called LTI 1.1. The University has phased out support for this technology, so courses need to be updated to use a newer, more secure standard called LTI 1.3. The steps below walk you through updating your course.</p><h2 id="remove-the-older-integration" tabindex="-1">Remove the older integration <a class="header-anchor" href="#remove-the-older-integration" aria-label="Permalink to &quot;Remove the older integration&quot;">​</a></h2><p>In your course settings, open the <strong>Apps</strong> tab, then click <strong>View App Configurations</strong>.</p><p><img src="'+o+'" alt="Canvas Apps tab and View App Configurations"></p><p>Scroll down and find an entry labeled <strong>ChimeIn 2</strong> with a gear icon. You may have multiple copies listed. Click the gear icon, then click <strong>Delete Placement</strong>.</p><p><img src="'+s+'" alt="Delete Placement option for an older ChimeIn app"></p><h2 id="update-assignments" tabindex="-1">Update assignments <a class="header-anchor" href="#update-assignments" aria-label="Permalink to &quot;Update assignments&quot;">​</a></h2><p>Edit each of your ChimeIn assignments and find the <strong>External Tool</strong> box. Click <strong>Find</strong>.</p><p><img src="'+i+'" alt="External Tool setting with Find button"></p><p>In the external tools list, select <strong>ChimeIn</strong>, then click <strong>Select</strong>.</p><p><img src="'+r+'" alt="External tool picker with ChimeIn selected"></p><p>Save the assignment. Repeat this process for all of your ChimeIn assignments.</p><p>Finally, click through one of your assignments. This will trigger the ChimeIn configuration page.</p>',14),c=[p];function h(d,g,m,u,_,f){return t(),n("div",null,c)}const v=e(l,[["render",h]]);export{I as __pageData,v as default};
